package router

import (
	"context"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

type Config struct {
	Port                  int
	EnableTLS             bool
	TLSCertFile           string
	TLSKeyFile            string
	Debug                 bool
	MaxConcurrentRequests int
	WorkloadManagerURL    string
	StoreType             string
	RedisAddr             string
	RedisPassword         string
	ValkeyAddr            string
	ValkeyPassword        string
	Namespace             string
}

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	jwtManager     *JWTManager
	sessionManager SessionManager
	httpTransport  *http.Transport
	once           sync.Once
}

type SessionManager interface {
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error)
	CreateSandbox(ctx context.Context, kind, name, namespace string) (*SandboxInfo, error)
}

type SandboxInfo struct {
	SessionID   string        `json:"sessionId"`
	SandboxID   string        `json:"sandboxId"`
	SandboxName string        `json:"sandboxName"`
	EntryPoints []EntryPoint  `json:"entryPoints"`
	ExpiresAt   time.Time     `json:"expiresAt"`
}

type EntryPoint struct {
	Name     string `json:"name"`
	Port     uint32 `json:"port"`
	Protocol string `json:"protocol"`
	Path     string `json:"path"`
	Endpoint string `json:"endpoint"`
}

func NewServer(config *Config) (*Server, error) {
	if config.Debug {
		gin.SetMode(gin.DebugMode)
	} else {
		gin.SetMode(gin.ReleaseMode)
	}

	jwtManager := NewJWTManager()
	if err := jwtManager.TryStoreOrLoadJWTKeySecret(config.Namespace); err != nil {
		klog.Warningf("Failed to initialize JWT keys: %v", err)
	}

	httpTransport := &http.Transport{
		MaxIdleConns:        100,
		MaxIdleConnsPerHost: 100,
		IdleConnTimeout:     90 * time.Second,
	}

	server := &Server{
		config:        config,
		engine:        gin.New(),
		jwtManager:    jwtManager,
		httpTransport: httpTransport,
	}

	server.engine.Use(gin.Logger(), gin.Recovery())
	server.registerRoutes()

	return server, nil
}

func (s *Server) SetSessionManager(sm SessionManager) {
	s.sessionManager = sm
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1 := s.engine.Group("/v1")
	v1.Use(s.concurrencyMiddleware())

	v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
	v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
	v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
}

func (s *Server) concurrencyMiddleware() gin.HandlerFunc {
	maxConcurrent := s.config.MaxConcurrentRequests
	if maxConcurrent <= 0 {
		maxConcurrent = 1000
	}

	semaphore := make(chan struct{}, maxConcurrent)

	return func(c *gin.Context) {
		select {
		case semaphore <- struct{}{}:
			defer func() { <-semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error":  "server overloaded, try again later",
				"code":   "SERVER_OVERLOADED",
			})
			c.Abort()
		}
	}
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not_ready",
			"error":  "session manager not initialized",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) resolveSession(c *gin.Context, kind, name, namespace string) (*SandboxInfo, error) {
	sessionID := c.GetHeader("x-agentcube-session-id")

	if sessionID == "" {
		if s.sessionManager == nil {
			return nil, fmt.Errorf("session manager not initialized")
		}
		sandbox, err := s.sessionManager.CreateSandbox(c.Request.Context(), kind, name, namespace)
		if err != nil {
			return nil, err
		}
		return sandbox, nil
	}

	if s.sessionManager == nil {
		return nil, fmt.Errorf("session manager not initialized")
	}
	sandbox, err := s.sessionManager.GetSandboxBySessionID(c.Request.Context(), sessionID)
	if err != nil {
		return nil, err
	}
	return sandbox, nil
}

func (s *Server) selectEntryPoint(entryPoints []EntryPoint, path string) *EntryPoint {
	if len(entryPoints) == 0 {
		return nil
	}

	for _, ep := range entryPoints {
		if ep.Path != "" && len(path) >= len(ep.Path) {
			if path[:len(ep.Path)] == ep.Path {
				return &ep
			}
		}
	}

	return &entryPoints[0]
}

func (s *Server) createProxy(targetURL *url.URL, sessionID, kind, namespace string) *httputil.ReverseProxy {
	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport

	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)
		req.Header.Set("x-agentcube-session-id", sessionID)
		req.Header.Set("x-forwarded-proto", "http")
		if cIP := c.RemoteAddr(); cIP != "" {
			req.Header.Set("x-forwarded-for", cIP)
		}
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		klog.Errorf("Proxy error for session %s: %v", sessionID, err)
		w.WriteHeader(http.StatusBadGateway)
		w.Write([]byte(fmt.Sprintf(`{"error":"proxy error: %v"}`, err)))
	}

	return proxy
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sandbox, err := s.resolveSession(c, "AgentRuntime", name, namespace)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": fmt.Sprintf("failed to resolve session: %v", err),
		})
		return
	}

	entryPoint := s.selectEntryPoint(sandbox.EntryPoints, path)
	if entryPoint == nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "no entrypoint available",
		})
		return
	}

	protocol := "http"
	if entryPoint.Protocol != "" {
		protocol = entryPoint.Protocol
	}
	if protocol == "HTTPS" {
		protocol = "https"
	} else {
		protocol = "http"
	}

	targetURL := &url.URL{
		Scheme: protocol,
		Host:   entryPoint.Endpoint,
	}

	proxy := s.createProxy(targetURL, sandbox.SessionID, "AgentRuntime", namespace)
	proxy.ServeHTTP(c.Writer, c.Request)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sandbox, err := s.resolveSession(c, "CodeInterpreter", name, namespace)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": fmt.Sprintf("failed to resolve session: %v", err),
		})
		return
	}

	entryPoint := s.selectEntryPoint(sandbox.EntryPoints, path)
	if entryPoint == nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "no entrypoint available",
		})
		return
	}

	protocol := "http"
	if entryPoint.Protocol != "" {
		protocol = entryPoint.Protocol
	}
	if protocol == "HTTPS" {
		protocol = "https"
	} else {
		protocol = "http"
	}

	targetURL := &url.URL{
		Scheme: protocol,
		Host:   entryPoint.Endpoint,
	}

	proxy := s.createProxy(targetURL, sandbox.SessionID, "CodeInterpreter", namespace)
	proxy.ServeHTTP(c.Writer, c.Request)
}

func (s *Server) Start() error {
	addr := fmt.Sprintf(":%d", s.config.Port)
	s.httpServer = &http.Server{
		Addr:         addr,
		Handler:      s.engine,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 60 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	klog.Infof("Router starting on %s", addr)
	if err := s.httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		return fmt.Errorf("server failed: %w", err)
	}
	return nil
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer == nil {
		return nil
	}
	klog.Info("Router shutting down...")
	return s.httpServer.Shutdown(ctx)
}

