func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sandbox, err := s.resolveSession(c, "CodeInterpreter", name, namespace)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": fmt.Sprintf("failed to resolve session: %v", err),
		})
		return
	}

	entryPoint := s.selectEntryPoint(sandbox.EntryPoints, path)
	if entryPoint == nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "no entrypoint available",
		})
		return
	}

	protocol := "http"
	if entryPoint.Protocol != "" {
		protocol = entryPoint.Protocol
	}
	if protocol == "HTTPS" {
		protocol = "https"
	} else {
		protocol = "http"
	}

	targetURL := &url.URL{
		Scheme: protocol,
		Host:   entryPoint.Endpoint,
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport
	proxy.Director = func(req *http.Request) {
