	}

	targetURL := &url.URL{
		Scheme: "http",
		Host:   "backend:8080",
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = server.httpTransport
	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.Host = targetURL.Host
		req.Header.Set("x-agentcube-session-id", "test-session")
		req.Header.Set("x-forwarded-proto", "http")
		req.Header.Set("x-forwarded-for", "192.168.1.1")
	}

	req := httptest.NewRequest("GET", "http://localhost/test", nil)
	proxy.Director(req)

	if req.Header.Get("x-agentcube-session-id") != "test-session" {
		t.Errorf("Expected session header, got %s", req.Header.Get("x-agentcube-session-id"))
	}

	if req.Header.Get("x-forwarded-proto") != "http" {
