	Stderr    string `json:"stderr"`
	ExitCode  int    `json:"exit_code"`
	Duration  string `json:"duration"`
	StartTime string `json:"start_time"`
	EndTime   string `json:"end_time"`
}

type Claims struct {
	jwt.RegisteredClaims
	SessionID string `json:"sessionId"`
	Kind      string `json:"kind"`
	Namespace string `json:"namespace"`
}

type FileUploadRequest struct {
	Path    string `json:"path"`
	Content string `json:"content,omitempty"`
	Mode    string `json:"mode,omitempty"`
}

type FileInfo struct {
	Name     string    `json:"name"`
	Size     int64     `json:"size"`
	Modified time.Time `json:"modified"`
	Mode     string    `json:"mode"`
	IsDir    bool      `json:"is_dir"`
}

type FileListResponse struct {
	Files []FileInfo `json:"files"`
}

type HealthResponse struct {
	Status  string `json:"status"`
	Service string `json:"service"`
	Version string `json:"version"`
	Uptime  string `json:"uptime"`
}

func NewServer(config *Config) (*Server, error) {
	gin.SetMode(gin.ReleaseMode)

	workspaceDir := config.Workspace
	if workspaceDir == "" {
		workspaceDir = "/tmp/picod-workspace"
	}

	if err := os.MkdirAll(workspaceDir, 0755); err != nil {
		return nil, fmt.Errorf("failed to create workspace: %w", err)
	}

	absWorkspace, err := filepath.Abs(workspaceDir)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve workspace path: %w", err)
	}

	server := &Server{
		config:       config,
		engine:       gin.New(),
		startTime:    time.Now(),
		workspaceDir: absWorkspace,
	}

	if config.PublicKey != "" {
		if err := server.loadPublicKey(config.PublicKey); err != nil {
			return nil, fmt.Errorf("failed to load public key: %w", err)
		}
	}

	server.engine.Use(gin.Logger(), gin.Recovery())
	server.registerRoutes()

	return server, nil
}

func (s *Server) loadPublicKey(pemEncoded string) error {
	keyData := []byte(pemEncoded)
	parsedKey, err := jwt.ParseRSAPublicKeyFromPEM(keyData)
	if err != nil {
		return fmt.Errorf("failed to parse RSA public key: %w", err)
	}

	s.mu.Lock()
	s.publicKey = parsedKey
	s.mu.Unlock()

	klog.Info("Loaded PicoD public key")
	return nil
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health", s.healthCheckHandler)

	api := s.engine.Group("/api")
	if s.publicKey != nil {
		api.Use(s.authMiddleware())
	}
	api.Use(s.maxBodySizeMiddleware(32 << 20))

	api.POST("/execute", s.executeHandler)
	api.POST("/files", s.uploadFileHandler)
	api.GET("/files", s.listFilesHandler)
	api.GET("/files/*path", s.downloadFileHandler)
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			c.Abort()
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization format"})
			c.Abort()
			return
		}

		tokenString := parts[1]
		s.mu.RLock()
		publicKey := s.publicKey
		s.mu.RUnlock()

		if publicKey == nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "authentication not configured"})
			c.Abort()
			return
		}

		token, err := jwt.ParseWithClaims(tokenString, &Claims{}, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return publicKey, nil
		}, jwt.WithLeeway(1*time.Minute))

		if err != nil {
			c.JSON(http.StatusUnauthorized, gin.H{"error": fmt.Sprintf("invalid token: %v", err)})
			c.Abort()
			return
		}

		claims, ok := token.Claims.(*Claims)
		if !ok || !token.Valid {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid token claims"})
			c.Abort()
			return
		}

		c.Set("sessionID", claims.SessionID)
		c.Set("namespace", claims.Namespace)
		c.Next()
	}
}

func (s *Server) maxBodySizeMiddleware(maxBytes int64) gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, maxBytes)
		c.Next()
	}
}

func (s *Server) sanitizePath(requestedPath string) (string, error) {
	if requestedPath == "" {
		requestedPath = "/"
	}

	cleanPath := filepath.Clean(requestedPath)
	if filepath.IsAbs(cleanPath) {
		cleanPath = cleanPath[1:]
	}

	fullPath := filepath.Join(s.workspaceDir, cleanPath)

	absWorkspace, err := filepath.Abs(s.workspaceDir)
	if err != nil {
		return "", fmt.Errorf("failed to resolve workspace: %w", err)
	}

	absFullPath, err := filepath.Abs(fullPath)
	if err != nil {
		return "", fmt.Errorf("failed to resolve full path: %w", err)
	}

	if !strings.HasPrefix(absFullPath, absWorkspace) {
		return "", fmt.Errorf("path escape detected")
	}

	absResolved, err := filepath.EvalSymlinks(fullPath)
	if err != nil {
		if os.IsNotExist(err) {
			return fullPath, nil
		}
		return "", err
	}

	if !strings.HasPrefix(absResolved, absWorkspace) {
		return "", fmt.Errorf("symlink escape detected")
	}

	return absResolved, nil
}

func (s *Server) healthCheckHandler(c *gin.Context) {
	uptime := time.Since(s.startTime)
	c.JSON(http.StatusOK, HealthResponse{
		Status:  "ok",
		Service: "PicoD",
		Version: "0.0.1",
		Uptime:  uptime.String(),
	})
}

func (s *Server) executeHandler(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid request body: %v", err)})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "command is required"})
		return
	}

	timeout := 60 * time.Second
	if req.Timeout != "" {
		var err error
		timeout, err = time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid timeout format: %v", err)})
			return
		}
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)
	cmd.Env = os.Environ()
	for k, v := range req.Env {
		cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
	}

	if req.WorkingDir != "" {
		sanitizedWd, err := s.sanitizePath(req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid working_dir: %v", err)})
			return
		}
		cmd.Dir = sanitizedWd
	}

	stdoutPipe, err := cmd.StdoutPipe()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create stdout pipe: %v", err)})
		return
	}

	stderrPipe, err := cmd.StderrPipe()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create stderr pipe: %v", err)})
		return
	}

	startTime := time.Now()
	if err := cmd.Start(); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to start command: %v", err)})
		return
	}

	stdoutChan := make(chan string, 1)
	stderrChan := make(chan string, 1)

	go func() {
		out, _ := io.ReadAll(stdoutPipe)
		stdoutChan <- string(out)
	}()

	go func() {
		err, _ := io.ReadAll(stderrPipe)
		stderrChan <- string(err)
	}()

	<-ctx.Done()

	var exitCode int
	if cmd.ProcessState != nil {
		exitCode = cmd.ProcessState.ExitCode()
	} else {
		exitCode = 124
	}

	stdout := <-stdoutChan
	stderr := <-stderrChan
	endTime := time.Now()
	duration := endTime.Sub(startTime)

	c.JSON(http.StatusOK, ExecuteResponse{
		Stdout:    stdout,
		Stderr:    stderr,
		ExitCode:  exitCode,
		Duration:  duration.String(),
		StartTime: startTime.Format(time.RFC3339),
		EndTime:   endTime.Format(time.RFC3339),
	})
}

func (s *Server) uploadFileHandler(c *gin.Context) {
	contentType := c.ContentType()

	if strings.HasPrefix(contentType, "application/json") {
		s.handleJSONUpload(c)
	} else if strings.HasPrefix(contentType, "multipart/") {
		s.handleMultipartUpload(c)
	} else {
		c.JSON(http.StatusBadRequest, gin.H{"error": "unsupported content type"})
	}
}

func (s *Server) handleJSONUpload(c *gin.Context) {
	var req FileUploadRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid request body: %v", err)})
		return
	}

	if req.Path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required"})
		return
	}

	sanitizedPath, err := s.sanitizePath(req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid path: %v", err)})
		return
	}

	fileMode := os.FileMode(0644)
	if req.Mode != "" {
		fmt.Sscanf(req.Mode, "%o", &fileMode)
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directory: %v", err)})
		return
	}

	var content []byte
	if req.Content != "" {
		content, err = base64.StdEncoding.DecodeString(req.Content)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("failed to decode content: %v", err)})
			return
		}
	}

	if err := os.WriteFile(sanitizedPath, content, fileMode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err)})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "file uploaded successfully", "path": req.Path})
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	form, err := c.MultipartForm()
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("failed to parse multipart form: %v", err)})
		return
	}

	pathValues := form.Value["path"]
	if len(pathValues) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required"})
		return
	}
	path := pathValues[0]

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid path: %v", err)})
		return
	}

	modeValues := form.Value["mode"]
	fileMode := os.FileMode(0644)
	if len(modeValues) > 0 && modeValues[0] != "" {
		fmt.Sscanf(modeValues[0], "%o", &fileMode)
	}

	files := form.File["file"]
	if len(files) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "file is required"})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directory: %v", err)})
		return
	}

	if err := c.SaveUploadedFile(files[0], sanitizedPath); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to save file: %v", err)})
		return
	}

	os.Chmod(sanitizedPath, fileMode)

	c.JSON(http.StatusOK, gin.H{"message": "file uploaded successfully", "path": path})
}

func (s *Server) listFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path parameter is required"})
		return
	}

	sanitizedPath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid path: %v", err)})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "directory not found"})
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to read directory: %v", err)})
		}
		return
	}

	files := make([]FileInfo, 0, len(entries))
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		files = append(files, FileInfo{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime(),
			Mode:     info.Mode().String(),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, FileListResponse{Files: files})
}

func (s *Server) downloadFileHandler(c *gin.Context) {
	requestedPath := c.Param("path")
	if requestedPath == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required"})
