)

func createTestServer(t *testing.T) (*Server, string) {
	tmpDir := t.TempDir()
	config := &Config{
		Port:      8080,
		Workspace: tmpDir,
	}

	server, err := NewServer(config)
	if err != nil {
		t.Fatalf("Failed to create server: %v", err)
	}

	return server, tmpDir
}

func generateTestToken(t *testing.T, server *Server) string {
	privateKey, err := jwt.ParseRSAPrivateKeyFromPEM([]byte(testPrivateKey))
	if err != nil {
		t.Fatalf("Failed to parse private key: %v", err)
	}

	claims := &Claims{
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(time.Now().Add(5 * time.Minute)),
			IssuedAt:  jwt.NewNumericDate(time.Now()),
		},
		SessionID: "test-session",
		Kind:      "CodeInterpreter",
		Namespace: "default",
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	signed, err := token.SignedString(privateKey)
	if err != nil {
		t.Fatalf("Failed to sign token: %v", err)
	}

	return signed
}

func TestHealthCheckHandler(t *testing.T) {
	server, _ := createTestServer(t)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/health", nil)
	server.engine.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status 200, got %d", w.Code)
	}

	var response HealthResponse
	if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
		t.Fatalf("Failed to parse response: %v", err)
	}

	if response.Status != "ok" {
		t.Errorf("Expected status 'ok', got '%s'", response.Status)
	}

	if response.Service != "PicoD" {
		t.Errorf("Expected service 'PicoD', got '%s'", response.Service)
	}
}

