type MockSessionManager struct {
	sandboxes map[string]*SandboxInfo
	createErr error
	getErr    error
}

func NewMockSessionManager() *MockSessionManager {
	return &MockSessionManager{
		sandboxes: make(map[string]*SandboxInfo),
	}
}

func (m *MockSessionManager) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	if m.getErr != nil {
		return nil, m.getErr
	}
	sandbox, ok := m.sandboxes[sessionID]
	if !ok {
		return nil, http.ErrMissingFile
	}
	return sandbox, nil
}

func (m *MockSessionManager) CreateSandbox(ctx context.Context, kind, name, namespace string) (*SandboxInfo, error) {
	if m.createErr != nil {
		return nil, m.createErr
	}
	sessionID := "test-session-" + name
	sandbox := &SandboxInfo{
		SessionID:   sessionID,
		SandboxID:   "test-sandbox-id",
		SandboxName: name,
		EntryPoints: []EntryPoint{
