func TestConcurrencyMiddleware(t *testing.T) {
	config := &Config{
		Port:                  8080,
		Debug:                 true,
		MaxConcurrentRequests: 2,
	}

	server, err := NewServer(config)
	if err != nil {
		t.Fatalf("Failed to create server: %v", err)
	}

	done := make(chan int, 3)
	for i := 0; i < 3; i++ {
		go func() {
			w := httptest.NewRecorder()
			req, _ := http.NewRequest("GET", "/v1/namespaces/test/agent-runtimes/test/invocations/test", nil)
			server.engine.ServeHTTP(w, req)
			done <- w.Code
		}()
	}

	successes := 0
	timeouts := 0
	for i := 0; i < 3; i++ {
		code := <-done
		if code == http.StatusOK || code == http.StatusNotFound {
			successes++
		} else if code == http.StatusTooManyRequests {
			timeouts++
		}
	}

	if timeouts < 1 {
		t.Error("Expected at least one request to be rate limited")
	}
}

func TestSelectEntryPoint(t *testing.T) {
	config := &Config{
		Port:  8080,
		Debug: true,
	}

	server, err := NewServer(config)
	if err != nil {
		t.Fatalf("Failed to create server: %v", err)
	}

	entryPoints := []EntryPoint{
		{Name: "api", Path: "/api", Port: 8080, Protocol: "HTTP", Endpoint: "10.0.0.1:8080"},
		{Name: "web", Path: "/web", Port: 8081, Protocol: "HTTP", Endpoint: "10.0.0.2:8081"},
	}

	ep := server.selectEntryPoint(entryPoints, "/api/v1/users")
	if ep == nil || ep.Name != "api" {
		t.Errorf("Expected 'api' endpoint, got %v", ep)
	}

	ep = server.selectEntryPoint(entryPoints, "/web/dashboard")
	if ep == nil || ep.Name != "web" {
		t.Errorf("Expected 'web' endpoint, got %v", ep)
	}

	ep = server.selectEntryPoint(entryPoints, "/unknown")
	if ep == nil || ep.Name != "api" {
		t.Errorf("Expected default 'api' endpoint, got %v", ep)
	}

	empty := []EntryPoint{}
	ep = server.selectEntryPoint(empty, "/api")
	if ep != nil {
		t.Errorf("Expected nil for empty entry points, got %v", ep)
	}
}

