	"time"
)

func createTestServer(t *testing.T) (*Server, string) {
	tmpDir := t.TempDir()
	config := &Config{
		Port:      8080,
		Workspace: tmpDir,
	}

	server, err := NewServer(config)
	if err != nil {
		t.Fatalf("Failed to create server: %v", err)
	}

	return server, tmpDir
}

func TestHealthCheckHandler(t *testing.T) {
	server, _ := createTestServer(t)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/health", nil)
	server.engine.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status 200, got %d", w.Code)
	}

	var response HealthResponse
	if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
		t.Fatalf("Failed to parse response: %v", err)
	}

	if response.Status != "ok" {
		t.Errorf("Expected status 'ok', got '%s'", response.Status)
	}

	if response.Service != "PicoD" {
		t.Errorf("Expected service 'PicoD', got '%s'", response.Service)
	}
}

func TestExecuteHandlerWithoutCommand(t *testing.T) {
	server, _ := createTestServer(t)

	w := httptest.NewRecorder()
	body := `{"command": []}`
	req, _ := http.NewRequest("POST", "/api/execute", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	server.engine.ServeHTTP(w, req)

	if w.Code != http.StatusBadRequest {
		t.Errorf("Expected status 400, got %d", w.Code)
	}
}

func TestExecuteHandlerWithInvalidTimeout(t *testing.T) {
	server, _ := createTestServer(t)

	w := httptest.NewRecorder()
	body := `{"command": ["echo", "hello"], "timeout": "invalid"}`
	req, _ := http.NewRequest("POST", "/api/execute", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	server.engine.ServeHTTP(w, req)

	if w.Code != http.StatusBadRequest {
		t.Errorf("Expected status 400, got %d", w.Code)
	}
}

func TestExecuteHandlerWithValidCommand(t *testing.T) {
	server, _ := createTestServer(t)

	w := httptest.NewRecorder()
	body := `{"command": ["echo", "hello"]}`
	req, _ := http.NewRequest("POST", "/api/execute", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	server.engine.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status 200, got %d - Body: %s", w.Code, w.Body.String())
	}

	var response ExecuteResponse
	if err := json.Unmarshal(w.Body.Bytes(), &response); err != nil {
		t.Fatalf("Failed to parse response: %v", err)
	}

	if response.ExitCode != 0 {
		t.Errorf("Expected exit code 0, got %d", response.ExitCode)
	}
}

func TestUploadFileJSONHandler(t *testing.T) {
	server, tmpDir := createTestServer(t)

	w := httptest.NewRecorder()
	content := base64.StdEncoding.EncodeToString([]byte("test content"))
	body := fmt.Sprintf(`{"path": "/test.txt", "content": "%s"}`, content)
	req, _ := http.NewRequest("POST", "/api/files", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	server.engine.ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Errorf("Expected status 200, got %d - Body: %s", w.Code, w.Body.String())
	}

