	data, err := os.ReadFile(filePath)
	if err != nil {
		t.Fatalf("Failed to read uploaded file: %v", err)
	}

	if string(data) != "test content" {
		t.Errorf("Expected 'test content', got '%s'", string(data))
	}
}

